const items = $input.all();
const today = new Date();
const urgent = [];
const upcoming = [];
const all = [];

for (const item of items) {
  const deadline = item.json.properties?.Deadline?.date?.start;
  const name = item.json.properties?.['Certificate Name']?.title?.[0]?.plainText || 'Unknown';
  const provider = item.json.properties?.Provider?.select?.name || 'Unknown';
  const status = item.json.properties?.Status?.status?.name || 'Not Started';
  const url = item.json.properties?.URL?.url || '';

  const entry = {
    name,
    provider,
    status,
    deadline: deadline || 'No deadline',
    url,
    daysLeft: deadline ? Math.ceil((new Date(deadline) - today) / (1000 * 60 * 60 * 24)) : null
  };

  all.push(entry);

  if (entry.daysLeft !== null && entry.daysLeft <= 7 && entry.daysLeft >= 0) {
    urgent.push(entry);
  } else if (entry.daysLeft !== null && entry.daysLeft <= 30 && entry.daysLeft > 7) {
    upcoming.push(entry);
  }
}

return [{
  json: {
    total: all.length,
    urgent,
    upcoming,
    all
  }
}];

const data = $input.first().json;
let message = '🎓 **Certificate Tracker Daily Report**\n\n';

if (data.urgent.length > 0) {
  message += '🚨 **URGENT (Due in 7 days):**\n';
  for (const cert of data.urgent) {
    message += `• ${cert.name} (${cert.provider}) - ${cert.daysLeft} days left\n`;
  }
  message += '\n';
}

if (data.upcoming.length > 0) {
  message += '📅 **Upcoming (30 days):**\n';
  for (const cert of data.upcoming) {
    message += `• ${cert.name} (${cert.provider}) - ${cert.daysLeft} days left\n`;
  }
  message += '\n';
}

message += `📊 **Total Active:** ${data.total} certificates\n\n`;

message += '**🏆 Recommended Free Certifications:**\n';
message += '1. Oracle OCI Foundations (FREE exam)\n';
message += '2. LinkedIn Learning (470+ free courses)\n';
message += '3. Google Skills Boost\n';
message += '4. Cisco Networking Academy\n';
message += '5. IBM SkillsBuild\n';
message += '6. Anthropic Academy (13 free courses)\n';
message += '7. Microsoft Learn Challenges\n';

return [{ json: { message } }];
